from flask import Flask, request, render_template, redirect, url_for, session, flash
import secrets
import hashlib
import time
from functools import wraps

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Mock user database
users = {
    "admin": {
        "password": hashlib.sha256("password123".encode()).hexdigest(),
        "mfa_secret": "GJ423759"
    }
}

# Mock MFA verification
def verify_mfa(user_id, token):
    # In a real app, this would verify against TOTP
    return token == users[user_id]["mfa_secret"]

# Login required decorator
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
def index():
    return "Welcome to the protected area!"

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users:
            hashed_password = hashlib.sha256(password.encode()).hexdigest()
            if hashed_password == users[username]["password"]:
                session['user_id'] = username
                session['mfa_verified'] = False
                return redirect(url_for('verify_mfa'))
        
        flash('Invalid username or password')
        return redirect(url_for('login'))
    
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'user_id' not in session:
        return redirect(url_for('login'))
    
    if session.get('mfa_verified', False):
        return redirect(url_for('index'))
    
    if request.method == 'POST':
        token = request.form['token']
        if verify_mfa(session['user_id'], token):
            session['mfa_verified'] = True
            return redirect(url_for('index'))
        else:
            flash('Invalid MFA token')
    
    return render_template('verify_mfa.html')

@app.route('/protected')
@login_required
def protected():
    if not session.get('mfa_verified', False):
        return redirect(url_for('verify_mfa'))
    return "This is a protected resource!"

if __name__ == '__main__':
    app.run(debug=True)